const allInputs = $input.all();

function extractArray(input) {
  if (!input || !input.json) return [];
  const data = input.json;
  if (Array.isArray(data)) return data;
  if (data.data && Array.isArray(data.data)) return data.data;
  if (data.values && Array.isArray(data.values)) return data.values;
  if (data.results && Array.isArray(data.results)) return data.results;
  if (typeof data === 'object') {
    const keys = Object.keys(data);
    const possibleArray = keys.map(k => data[k]).filter(v => v !== null && typeof v === 'object');
    if (possibleArray.length > 0) return possibleArray;
  }
  return [];
}

const menuItems = extractArray(allInputs[0]);
const extrasItems = extractArray(allInputs[1]);
const bebidasItems = extractArray(allInputs[2]);

const products = menuItems.map(row => ({
  id: row['id'] || row['ID'] || row['Id'],
  name: row['name'] || row['Nombre'] || row['NAME'],
  description: row['description'] || row['Description'] || '',
  price: parseInt(row['price'] || row['Price'] || row['precio'] || 0),
  size: row['size'] || row['Size'] || 'Mediana',
  category: row['category'] || row['Category'] || row['categoria'] || 'General',
  active: (row['active'] || row['Active'] || 'TRUE').toString().toUpperCase() === 'TRUE',
  type: 'pizza'
})).filter(p => p.active && p.name);

const extras = extrasItems.map(row => ({
  name: row['name'] || row['Nombre'] || row['NAME'],
  price: parseInt(row['price'] || row['Price'] || row['precio'] || 0),
  type: 'extra'
})).filter(e => e.name && e.price > 0);

const bebidas = bebidasItems.map(row => ({
  id: row['id'] || row['ID'],
  name: row['name'] || row['Nombre'] || row['NAME'],
  description: row['description'] || '',
  price: parseInt(row['price'] || row['Price'] || row['precio'] || 0),
  type: 'bebida'
})).filter(b => b.name && b.price > 0);

return [{
  json: {
    products,
    extras,
    bebidas,
    totalItems: products.length + extras.length + bebidas.length
  }
}];
